// Insert bulk community posts+comments generated by the workflow.
// Usage: node scripts/insert-bulk-community.js <path-to-posts.json>
// The JSON must be { posts: [ { category, tone, title, content, author_name, is_anonymous, comments:[...] } ] }
require('dotenv').config({ path: '.env.local' })
const fs = require('fs')
const { createClient } = require('@supabase/supabase-js')

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
)

const BIG = ['Grab', 'Shopee', 'VNG', 'FPT Software', 'Viettel', 'MoMo', 'VNPAY', 'Tiki', 'Vingroup', 'Techcombank', 'Be Group', 'Lazada', 'Sea Group', 'Zalo']
const STARTUP = ['Sky Mavis', 'Coolmate', 'Katalon', 'Holistics', 'Base.vn', 'Got It', 'Elsa', 'Finhay', 'Timo', 'Lozi']

const rint = (a, b) => Math.floor(a + Math.random() * (b - a + 1))
const pick = arr => arr[rint(0, arr.length - 1)]
const DAY = 86400000

function maskName(name) {
  if (!name) return 'Ẩn danh'
  const ch = name.trim().charAt(0)
  return ch + '**'
}

// commenter employment: ~33% unemployed, ~52% big company, ~15% startup
function commenterCompany() {
  const r = Math.random()
  if (r < 0.33) return { is_salary_verified: false, author_company: null }
  if (r < 0.85) return { is_salary_verified: true, author_company: pick(BIG) }
  return { is_salary_verified: true, author_company: pick(STARTUP) }
}

// view distribution: viral / normal / low; likes are PROPORTIONAL to views (~0.4-4.9%)
function postStats() {
  const r = Math.random()
  let view
  if (r < 0.12) view = rint(1800, 6000)        // viral
  else if (r < 0.80) view = rint(120, 900)     // normal
  else view = rint(15, 110)                     // low
  const ratio = 0.004 + Math.pow(Math.random(), 2) * 0.045  // mostly low, occasional hot post
  return { view_count: view, like_count: Math.max(0, Math.round(view * ratio)) }
}

// comment likes: mostly 0-3, occasionally higher
const commentLikes = () => Math.round(Math.pow(Math.random(), 2.6) * 20)

async function main() {
  const file = process.argv[2]
  if (!file) { console.error('Usage: node scripts/insert-bulk-community.js <posts.json>'); process.exit(1) }
  const { posts } = JSON.parse(fs.readFileSync(file, 'utf8'))
  if (!Array.isArray(posts) || !posts.length) { console.error('No posts in file'); process.exit(1) }

  const { data: list } = await supabase.auth.admin.listUsers({ perPage: 1000 })
  const sys = (list.users || []).find(u => u.email === 'community@system.local')
  if (!sys) { console.error('system account missing'); process.exit(1) }

  const now = Date.now()
  let okPosts = 0, okComments = 0, failed = 0

  for (const p of posts) {
    // created_at: spread across the past ~1..75 days (shuffled by randomness)
    const postTime = now - rint(1, 75) * DAY - rint(0, 23) * 3600000 - rint(0, 59) * 60000
    const stats = postStats()
    const comments = Array.isArray(p.comments) ? p.comments : []

    const { data: post, error: pe } = await supabase.from('community_posts').insert({
      user_id: sys.id,
      author_name: p.is_anonymous ? maskName(p.author_name) : p.author_name,
      category: ['daily', 'job_change', 'ask_company'].includes(p.category) ? p.category : 'daily',
      title: p.title,
      content: p.content,
      is_anonymous: !!p.is_anonymous,
      like_count: stats.like_count,
      view_count: stats.view_count,
      comment_count: comments.length,
      // post author shown as unemployed (avoids contradicting the body)
      is_salary_verified: false,
      author_company: null,
      created_at: new Date(postTime).toISOString(),
    }).select('id').single()

    if (pe || !post) { failed++; console.error('post fail:', pe && pe.message); continue }
    okPosts++

    // comments: spaced after the post, never in the future
    const rows = comments.map((c, idx) => {
      const span = Math.max(now - postTime - 60000, 60000)
      const ct = postTime + 600000 + Math.floor(Math.random() * span)
      const co = commenterCompany()
      return {
        post_id: post.id,
        user_id: sys.id,
        author_name: c.is_anonymous ? maskName(c.author_name) : c.author_name,
        content: c.content,
        is_anonymous: !!c.is_anonymous,
        is_op: !!c.is_op,
        like_count: commentLikes(),
        is_salary_verified: co.is_salary_verified,
        author_company: co.author_company,
        created_at: new Date(Math.min(ct, now - 30000)).toISOString(),
      }
    })
    if (rows.length) {
      const { error: ce } = await supabase.from('community_comments').insert(rows)
      if (ce) console.error('comments fail on post', post.id, ce.message)
      else okComments += rows.length
    }
  }

  console.log(`\n삽입 완료: 글 ${okPosts}개 / 댓글 ${okComments}개 / 실패 ${failed}`)
}

main().catch(e => { console.error('ERR:', e.message); process.exit(1) })
